import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    private static long mergeSort(long[] a, int l, int r, long[] tmp) {
        if (l >= r) return 0;
        int m = l + (r - l) / 2;
        long cnt = 0;
        cnt += mergeSort(a, l, m, tmp);
        cnt += mergeSort(a, m + 1, r, tmp);
        int i = l, j = m + 1;
        while (i <= m) {
            while (j <= r && a[i] > 2L * a[j]) j++;
            cnt += j - (m + 1);
            i++;
        }
        int p = l, q = m + 1, k = l;
        while (p <= m && q <= r) {
            if (a[p] <= a[q]) tmp[k++] = a[p++];
            else tmp[k++] = a[q++];
        }
        while (p <= m) tmp[k++] = a[p++];
        while (q <= r) tmp[k++] = a[q++];
        for (p = l; p <= r; p++) a[p] = tmp[p];
        return cnt;
    }

    public static void main(String[] args) throws Exception {
        // Read entire input, replace escaped newlines with spaces, then tokenize.
        String data = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        data = data.replace("\\n", " ");
        data = data.replace('\r', ' ');
        StringTokenizer st = new StringTokenizer(data);
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(st.nextToken());
        while (T-- > 0) {
            int N = Integer.parseInt(st.nextToken());
            long[] arr = new long[N];
            for (int i = 0; i < N; i++) {
                arr[i] = Long.parseLong(st.nextToken());
            }
            long[] tmp = new long[N];
            long ans = mergeSort(arr, 0, N - 1, tmp);
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

